using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentService
{
    private readonly HttpClient _http;

    public ShipmentService(HttpClient http)
    {
        _http = http;
    }

    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await _http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];
    }

    public async Task<Shipment?> GetByTrackingNumberAsync(string trackingNumber)
    {
        var response = await _http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<Shipment>();
        return null;
    }

    public async Task<Shipment?> UpdateStatusAsync(int id, ShipmentStatus status)
    {
        var response = await _http.PutAsJsonAsync($"api/shipments/{id}/status", status);
        if (response.IsSuccessStatusCode)
            return await response.Content.ReadFromJsonAsync<Shipment>();
        return null;
    }
}

@page "/dispatcher"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Microsoft.AspNetCore.Authorization.Authorize(Roles = "Dispatcher")]
@inject ShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

@if (shipments is null)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Filter by destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th @onclick="() => SortBy(nameof(Shipment.TrackingNumber))" style="cursor:pointer">
                    Tracking # @SortIndicator(nameof(Shipment.TrackingNumber))
                </th>
                <th @onclick="() => SortBy(nameof(Shipment.Destination))" style="cursor:pointer">
                    Destination @SortIndicator(nameof(Shipment.Destination))
                </th>
                <th @onclick="() => SortBy(nameof(Shipment.Status))" style="cursor:pointer">
                    Status @SortIndicator(nameof(Shipment.Status))
                </th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <span class="badge @GetStatusBadge(shipment.Status)">
                            @shipment.Status
                        </span>
                    </td>
                    <td>@shipment.EstimatedDelivery.ToString("MMM dd, yyyy")</td>
                    <td>
                        <select class="form-select form-select-sm" style="width:auto;display:inline-block"
                                value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                </tr>
            }
        </tbody>
    </table>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<Shipment>? shipments;
    private string filterText = string.Empty;
    private string sortColumn = nameof(Shipment.TrackingNumber);
    private bool sortAscending = true;

    protected override async Task OnInitializedAsync()
    {
        shipments = await ShipmentService.GetAllShipmentsAsync();
    }

    private IEnumerable<Shipment> FilteredShipments =>
        (shipments ?? [])
            .Where(s => string.IsNullOrEmpty(filterText)
                || s.Destination.Contains(filterText, StringComparison.OrdinalIgnoreCase)
                || s.TrackingNumber.Contains(filterText, StringComparison.OrdinalIgnoreCase))
            .OrderBy(s => sortColumn switch
            {
                nameof(Shipment.Destination) => (object)s.Destination,
                nameof(Shipment.Status) => s.Status,
                _ => s.TrackingNumber
            })
            .ThenBy(s => sortAscending ? 0 : 1);

    private void SortBy(string column)
    {
        if (sortColumn == column)
            sortAscending = !sortAscending;
        else
        {
            sortColumn = column;
            sortAscending = true;
        }
    }

    private string SortIndicator(string column) =>
        sortColumn == column ? (sortAscending ? "▲" : "▼") : "";

    private async Task UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var newStatus))
        {
            var updated = await ShipmentService.UpdateStatusAsync(shipment.Id, newStatus);
            if (updated is not null)
            {
                shipment.Status = updated.Status;
                shipment.EstimatedDelivery = updated.EstimatedDelivery;
            }
        }
    }

    private static string GetStatusBadge(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-info",
        ShipmentStatus.Delayed => "bg-danger",
        ShipmentStatus.PickedUp => "bg-warning text-dark",
        _ => "bg-secondary"
    };
}

