using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments").RequireAuthorization();

        group.MapGet("/", [Authorize(Roles = "Dispatcher")] async (ApplicationDbContext db) =>
        {
            return await db.Shipments.OrderByDescending(s => s.ShippedDate).ToListAsync();
        });

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db, HttpContext context) =>
        {
            var shipment = await db.Shipments
                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);

            if (shipment is null)
                return Results.NotFound();

            return Results.Ok(shipment);
        });

        group.MapPut("/{id}/status", [Authorize(Roles = "Dispatcher")] async (int id, ShipmentStatus status, ApplicationDbContext db) =>
        {
            var shipment = await db.Shipments.FindAsync(id);
            if (shipment is null)
                return Results.NotFound();

            shipment.Status = status;

            // Adjust estimated delivery if delayed
            if (status == ShipmentStatus.Delayed)
                shipment.EstimatedDelivery = shipment.EstimatedDelivery.AddDays(2);

            await db.SaveChangesAsync();
            return Results.Ok(shipment);
        });
    }
}

using Microsoft.AspNetCore.Identity;
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Data;

